$scripts = @(
    {
        reg.exe add "HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\OOBE" /v BypassNRO /t REG_DWORD /d 1 /f;
    };
    #{
    #    # Bloco 1: Desativação de VBS/HVCI (Performance para Games)
    #    reg.exe add "HKLM\SYSTEM\CurrentControlSet\Control\DeviceGuard" /v EnableVirtualizationBasedSecurity /t REG_DWORD /d 0 /f;
    #    reg.exe add "HKLM\SYSTEM\CurrentControlSet\Control\DeviceGuard\Scenarios\HypervisorEnforcedCodeIntegrity" /v Enabled /t REG_DWORD /d 0 /f;
    #};
    #{
    #    # Bloco 2: Provisionamento WSL2 (Habilita recursos de Virtualização)
    #    Enable-WindowsOptionalFeature -Online -FeatureName Microsoft-Windows-Subsystem-Linux -All -NoRestart;
    #    Enable-WindowsOptionalFeature -Online -FeatureName VirtualMachinePlatform -All -NoRestart;
    #};
    {
        # Bloco 3: Desativação de Serviços (Telemetria, Spooler, Xbox)
        $services = @("DiagTrack", "dmwappushservice", "Spooler", "Fax", "XblAuthManager", "XblGameSave", "XboxNetApiSvc");
        foreach ($s in $services) {
            $svc = Get-Service -Name $s -ErrorAction SilentlyContinue;
            if ($svc) {
                $svc | Stop-Service -Force -ErrorAction SilentlyContinue;
                Set-Service -Name $s -StartupType Disabled -ErrorAction SilentlyContinue;
            }
        }
        Get-Service -Name "SysMain" -ErrorAction SilentlyContinue | Set-Service -StartupType Manual;
    };
    {
        # Bloco 4: Otimização de Rede (Desativa Algoritmo de Nagle)
        $interfaces = "HKLM\SYSTEM\CurrentControlSet\Services\Tcpip\Parameters\Interfaces";
        Get-ChildItem -Path "Registry::$interfaces" | ForEach-Object {
            reg.exe add $_.PSPath /v "TcpAckFrequency" /t REG_DWORD /d 1 /f;
            reg.exe add $_.PSPath /v "TCPNoDelay" /t REG_DWORD /d 1 /f;
        };
    };
    {
        # Bloco 5: Otimização de I/O e Sistema de Arquivos
        fsutil.exe behavior set disablecompression 1;
        reg.exe add "HKLM\SYSTEM\CurrentControlSet\Control\FileSystem" /v LongPathsEnabled /t REG_DWORD /d 1 /f;
    };
    {
        # Bloco 6: Configuração de Relógio UTC (Dual-Boot com Ubuntu)
        reg.exe add "HKLM\System\CurrentControlSet\Control\TimeZoneInformation" /v RealTimeIsUniversal /d 1 /t REG_DWORD /f;
    };
);

& {
